INSERT INTO public.news (title, slug, excerpt, content, tag, status, published_at) VALUES
('Rolê a Monte Verde reúne a turma na serra', 'role-monte-verde-reune-a-turma-na-serra', 'Saída cedo de Atibaia, parada estratégica pra café e um dia inteiro curtindo as curvas da serra. Foi rolê pra entrar pra história do clube.', 'Saída cedo de Atibaia, parada estratégica pra café e um dia inteiro curtindo as curvas da serra. Foi rolê pra entrar pra história do clube.\n\nMais detalhes em breve...', 'Passeio', 'published', NOW() - INTERVAL '2 days'),
('Por que a parada do café faz parte do roteiro', 'por-que-a-parada-do-cafe-faz-parte-do-roteiro', 'Mais do que combustível, o café é o pretexto pra conversa, pra rever a rota e pra deixar a estrada esperar mais um pouco.', 'Mais do que combustível, o café é o pretexto pra conversa, pra rever a rota e pra deixar a estrada esperar mais um pouco.\n\nSempre paramos naquele lugar especial.', 'Cultura', 'published', NOW() - INTERVAL '15 days'),
('Pedra Bela ao nascer do sol: como foi o último rolê', 'pedra-bela-ao-nascer-do-sol-como-foi-o-ultimo-role', 'Acordamos antes do galo cantar pra pegar o nascer do sol no mirante. O frio compensou — e as fotos também.', 'Acordamos antes do galo cantar pra pegar o nascer do sol no mirante. O frio compensou — e as fotos também.\n\nUma experiência inesquecível para todos os membros.', 'Bastidores', 'published', NOW() - INTERVAL '30 days')
